class Solution:
    def countSubarrays(self, nums):
        count = 0
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                for k in range(j + 1, n):
                    if k - i == 2 and (nums[i] + nums[k]) * 2 == nums[j]:
                        count += 1
        return count

