var countSubarrays = function(nums) {
    let count = 0;
    for (let i = 0; i < nums.length - 2; i++) {
        const a = nums[i], b = nums[i + 1], c = nums[i + 2];
        if (2 * (a + c) === b) count++;
    }
    return count;
